/** @internal */
export type DrawToolGeometryType = "point" | "multipoint" | "polyline" | "polygon" | "circle" | "rectangle" | "mesh";

/**
 * A plugin configuration includes the minimal information needed to integrate
 * a plugin implementation into the DrawTool and associated UI components.
 *
 * These should represent a configuration of a plugin that
 * exists as part of an editing workflow.
 *
 * @internal
 */
export interface PluginConfiguration {
  /**
   * A unique identifier for this plugin configuration.
   *
   * @internal
   */
  uniqueId: symbol;
  /**
   * Determines the proper roles for the plugin in the editing workflow.
   *
   * @internal
   */
  kind: ("multipart" | "part" | "section" | "vertex")[];
  /**
   * Determines the geometry type produced by the plugin. This influences the
   * root geometry type of the edit session created for the plugin.
   *
   * @internal
   */
  geometryType: "multipoint" | "point" | "polyline" | "polygon";
  /**
   * Indicates the types of curves the plugin is capable of contributing to the
   * shared geometry, if any.
   *
   * @internal
   */
  curveTypes?: CurveType[];
  /**
   * If true, the plugin will be hidden from UI components that list available plugins.
   * The plugin will be treated as an internal implementation detail of the parent plugin.
   *
   * @internal
   */
  hidden?: boolean;
  /**
   * Callback that can be used to asynchronously import and create an instance of the plugin.
   * This method should also be used to handle any configuration of the plugin instance.
   *
   * @returns a configured plugin instance.
   * @internal
   */
  create(): Plugin;
  /**
   * Can optionally define a downstream plugin that will be started automatically
   * if there is no downstream defined in the stack passed to the DrawTool.
   *
   * This is useful in cases where a plugin must manage downstream plugins to accomplish its task,
   * for example a polyline plugin might depend on a plugin that produces points, or other segments.
   *
   * @internal
   */
  defaultDownstreamPlugin?: PluginConfiguration;
  /**
   * Localization key for the plugin; used by UI components to look up the name of the plugin.
   *
   * @internal
   */
  localizationKey: string;
  /**
   * Icon name for the plugin; used by UI components to show an icon representing the plugin.
   *
   * @internal
   */
  icon: Icon["icon"];
  /**
   * The list of plugins that should be made available to select while this plugin is active.
   * For example, a polyline plugin might include point and curve plugins as available downstream plugins.
   *
   * @internal
   */
  availableDownstreamPlugins?: PluginConfiguration[];
  /**
   * A list of named editing tool GUIDs that should be associated with this plugin.
   * These GUIDs are typically published as part of shared templates.
   *
   * @internal
   */
  namedEditingToolGUIDs?: string[];
  /**
   * The corresponding legacy [CreateTool](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/types/#CreateTool) string, if any. Facilitates backwards compatibility
   * with pre-[Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin) [SketchViewModel](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/SketchViewModel/) workflows.
   *
   * @internal
   * @see [SketchViewModel.create()](https://developers.arcgis.com/javascript/latest/references/core/widgets/Sketch/SketchViewModel/#create)
   */
  legacyCreateTool?: CreateTool;
  /**
   * A list of view types that this plugin is not compatible with.
   *
   * @internal
   */
  excludedViews?: ("2d" | "3d" | "linkchart" | "video" | "map")[];
}

/** @internal */
export interface DrawToolCommandBase {}

/**
 * A request for action to be taken by DrawTool, optionally
 * including an underlying event payload.
 *
 * Some tools require the option to intercept and potentially
 * block nearly all DrawTool interactions; this is facilitated
 * by the `before-` events.
 *
 * @internal
 */
export interface SimpleDrawToolCommand extends DrawToolCommandBase {}

/**
 * Describes the role of a handle in the editing experience. This role will typically
 * be used to drive the appearance and behavior of the handle.
 *
 * - `"primary"`: a handle that is being used to manipulate a point, endpoint,
 *                or vertex in a geometry.
 * - `"secondary"`: a handle that is being used to manipulate a parameter being
 *                  used to generate geometry or otherwise influence geometry
 *                  creation without directly corresponding to a single vertex in
 *                  the output geometry. This includes points that serve as curve
 *                  control points/parameters.
 *
 * @internal
 */
export type InteractiveHandleRole = "primary" | "secondary";

/**
 * DrawTool uses capture modes to control how the user can interact with the handle.
 * This affects how input events are interpreted.
 *
 * Capture modes are important because some plugins need different behavior for their handles
 * than others. For example, the built-in streaming plugin needs to be able to capture input
 * while the user holds and drags.
 *
 * These capture modes are abstracted from the typical mouse concepts because DrawTool is intended
 * to support a wide variety of input methods. Capture mode should capture the general intent
 * for how the user interacts with the handle; DrawTool is responsible for making sure the handle
 * works in a manner compatible with that intent regardless of input method (keyboard, mouse, touch, gamepad, etc.)
 *
 * - grabbable-object: The handle is a static object locked at a map position. It can be hovered and it can be picked up and dragged.
 * - capture-always: The handle follows the user cursor always, snapping and emitting updates continuously.
 * - capture-when-engaged: The handle follows the cursor always, but only emits change events when the user has indicated,
 *                         for example by holding down the left mouse button. This is intended to enable streaming scenarios.
 *
 * @internal
 */
export type InteractiveHandleCaptureMode = "capture-always" | "capture-when-engaged" | "grabbable-object";

/**
 * An interactive handle is an on-screen object that can be used to manipulate the
 * creation of a drawing. Handles may follow the cursor position, have different presentations
 * (for example to differentiate between a vertex handle and a control point handle),
 * and can be interacted with in various ways.
 *
 * Handles, depending on configuration, are snapped and have field-driven and custom constraints
 * applied automatically.
 *
 * @internal
 */
export interface InteractiveHandle {
  /**
   * Controls the appearance and some behaviors of the handle. This is intended to support workflows
   * where there are multiple handles for a given plugin. For example, a plugin for drawing a true curve
   * might need a handle to set the endpoint of the curve, and one or more other handles to set
   * the control points of the curve.
   *
   * Valid values:
   *
   * - `primary`: generally should be used for handles that represent a point or vertex within
   *              the geometry. These handles are shown as a circle by default.
   * - `secondary`: generally should be used for handles that represent a parameter that is used
   *                in the generation of geometry, or as a non-endpoint parameter in a curve edge.
   *
   * Note: the Plugin system allows for plugins to apply behaviors that affect handles created
   *       other plugins in some cases. These behaviors may use this role. For example, the
   *       built-in polyline plugin might set up direction-distance fields and apply constraints
   *       for handles belonging to downstream plugins with the `primary` role set.
   *
   * @internal
   */
  role: InteractiveHandleRole;
  /**
   * Optional name that can be used to identify this handle. This can be used to support limiting
   * custom [Field](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Field) configurations to a specific handle.
   *
   * @internal
   */
  name?: string | null;
  /** @internal */
  editSession?: EditSession | null;
  /**
   * Tracks the current default capturing mode. DrawTool uses this to control how
   * the user can interact with the handle. In other words, this controls how input events
   * are interpreted to manipulate handles.
   *
   * Capture modes are important because some plugins need different behavior for their handles
   * than others. For example, the built-in streaming plugin needs to be able to capture input
   * while the user holds and drags.
   *
   * These capture modes are abstracted from the typical mouse concepts because DrawTool is intended
   * to support a wide variety of input methods. Capture mode should capture the general intent
   * for how the user interacts with the handle; DrawTool is responsible for making sure the handle
   * works in a manner compatible with that intent regardless of input method (keyboard, mouse, touch, gamepad, etc.)
   *
   * - grabbable-object: The handle is a static object locked at a map position. It can be hovered and it can be picked up and dragged.
   * - capture-always: The handle follows the user cursor always, snapping and emitting updates continuously.
   * - capture-when-engaged: The handle follows the cursor always, but only emits change events when the user has indicated,
   *                         for example by holding down the left mouse button. This is intended to enable streaming scenarios.
   *
   * Note: plugins may configure the default capture mode, but the actual capture mode is controlled
   * by DrawTool and is read only.
   *
   * @default "capture-always"
   * @internal
   */
  defaultCaptureMode: InteractiveHandleCaptureMode;
  /**
   * The current capture mode for the handle. This can change in response to user action. For
   * example, if the current handle is in `"capture-always"` mode, the user needs to be able
   * to temporarily disable this to be able to select a handle in `grabbable-object` mode.
   * Another possibility is that the DrawTool implementation enables the user to move between
   * handles using some other gesture, for example to enable keyboard accessibility.
   *
   * See `DefaultCaptureMode` for details.
   *
   * @default "capture-always"
   * @internal
   */
  get captureMode(): InteractiveHandleCaptureMode;
  /**
   * Controls whether this handle should be subject to snapping. This only takes
   * effect if the snapping system is enabled.
   *
   * @default true
   * @internal
   */
  snappingEnabled: boolean;
  /**
   * In some cases, self-snapping in particular is not appropriate.
   * This is generally true in cases where the handle does not
   * represent a proposed vertex on the edit geometry.
   *
   * An example is a bezier control point, or a shape creation plugin
   * where the handle is an input used to generate the shape.
   *
   * This property only takes effect if `snappingEnabled` is true.
   *
   * @default true
   * @internal
   */
  selfSnappingEnabled: boolean;
  /**
   * Map position of the cursor, ignoring snapping and constraints.
   *
   * @internal
   */
  inputMapPosition?: Point | null;
  /**
   * Map position of the cursor, after snapping and constraints have taken effect.
   *
   * @internal
   */
  get outputMapPosition(): Point | null | undefined;
  /**
   * When a drag starts when snapping is enabled, we snap that starting position.
   * This makes it possible to produce a snapped sketch for a drag shape (e.g. creating a rectangle).
   *
   * @internal
   */
  get outputMapPositionOfDragStart(): Point | null | undefined;
  /**
   * Map position of the cursor after snapping only; null if no snapping result.
   *
   * @internal
   */
  get selectedSnappingResult(): Point | null | undefined;
  /**
   * Returns the on-screen position of the manipulator
   *
   * @internal
   */
  get screenPosition(): ScreenPoint | null | undefined;
  /**
   * True if the cursor is being dragged.
   *
   * Note: this is not necessarily restricted to mouse drag; this concept may be implemented
   * in an input-agnostic way (for example, a gamepad could be used to 'drag' a cursor, e.g. by holding
   * down a button while moving the sticks).
   *
   * @internal
   */
  get dragging(): boolean;
}

/**
 * Used to enable plugins to access global state that may be set by one or more input methods,
 * or even default configuration passed to DrawTool at construction time.
 *
 * @internal
 */
export interface GlobalState {
  /**
   * Indicates whether aspect ratio should be locked while drawing.
   *
   * @internal
   */
  preserveAspectRatio: boolean;
  /**
   * Indicates whether any shapes should be centered.
   *
   * @internal
   */
  centered: boolean;
  /**
   * Controls how elevation (Z) values are determined when drawing
   * in a scene. If true, the cursor will generally be interpreted
   * as having a fixed Z/elevation value determined by the context
   * (for example, using the same value for all vertices in a polygon).
   *
   * @internal
   */
  drawAtFixedElevation: boolean;
}

/**
 * Describes the purpose of a visual in the drawing workflow. A visual's
 * role may affect its appearance and display order.
 *
 * Value | Description
 * ------|------------
 * `outputGeometry` | The main geometry being constructed by the DrawTool.
 * `outline` | An outline of the main geometry, either partial or complete.
 * `constructionLine` | A line that connects interactive handles but is not an edge in the geometry. For example, the line connecting an endpoint of a bezier curve to its control point.
 * `guide` | A non-interactive visual providing guidance to the user. For example, a point indicating the center of the circle containing a circular arc segment.
 * `vertex` | A vertex in a polygon or polyline.
 * `controlPoint` | An interactive handle used to manipulate some parameter of the geometry but that is not itself a vertex in the geometry. For example, a control point for a bezier curve.
 * `cursor` | A visual representing the current cursor position.
 *
 * @internal
 */
export type DrawToolVisualRole = "outputGeometry" | "outline" | "constructionLine" | "vertex" | "controlPoint" | "guide" | "cursor";

/**
 * Describes the current state of a visual in the drawing workflow.
 * State may affect the appearance or display order of the visual.
 *
 * Value | Description
 * ------|------------
 * `idle` | The visual is not being interacted with.
 * `focused` | The visual is focused but not yet active, for example because it is being hovered over.
 * `active` | The visual is currently being interacted with.
 *
 * @internal
 */
export type DrawToolVisualState = "active" | "idle" | "focused";

/** @internal */
export interface DrawToolGraphicProperties {
  /** @internal */
  geometry?: GeometryUnion | null;
  /** @internal */
  symbol?: SymbolUnion | null;
  /**
   * An integer determining the drawing order of the graphic relative to other
   * graphics. By default, graphics display in the order in which they were
   * first added to the renderer. This property can be used to override that
   * order. It should be used sparingly.
   *
   * @internal
   */
  zIndex: number;
}

/** @internal */
export interface DrawToolVisualProperties {
  /** @internal */
  geometry?: GeometryUnion | null;
  /**
   * Describes the purpose of the visual or what it represents in the
   * drawing workflow.
   *
   * @internal
   */
  role: DrawToolVisualRole;
  /**
   * Describes the current state of the visual, which may influence its
   * appearance.
   *
   * @internal
   */
  state: DrawToolVisualState;
}

/**
 * Default values for field order
 *
 * @internal
 */
export const knownFieldDisplayOrders: {
    AboveCoordinates: number;
    Coordinates: number;
    Middle: number;
    BelowMiddle: number;
    ShapeMeasurements: number;
};

/**
 * Built-in field configurations.
 *
 * @internal
 */
export type FieldPreset = "area" | "direction" | "distance" | "elevation" | "latitude" | "longitude" | "orientation" | "radius" | "scale" | "size" | "totalLength" | "x" | "y" | "generic-length" | "generic-angle" | "generic-area" | "generic-scalar";

/**
 * Properties that can be used to configure a custom field.
 *
 * See [FieldPreset](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#FieldPreset) for convenient built-in fields.
 *
 * @internal
 */
export type CustomFieldProperties<T> = TooltipFieldRequiredProperties<T>
  & Partial<Field<T>>
  & {
  /**
   * Optional group parameter to group this field for side-by-side display.
   * Useful for showing non-editable width and height values.
   *
   * This should not be set on editable fields, or in situations where the field
   * should be given full width when presented to the user.
   *
   * @internal
   */
  displayGroup?: Symbol | null;
};

/**
 * Filters that limit a field to a particular handle either by name or by role.
 *
 * @internal
 */
export interface CustomFieldAppliesToProperties {}

/**
 * Fields enable plugins to provide feedback to the user as well as gather input.
 *
 * Fields are typically presented in tooltips, although exact details of how
 * fields are presented to the user are subject to change.
 *
 * Esri built-in drawing experiences will show fields in a tooltip; the fields contributed
 * by all active plugins are aggregated into a single
 * form that is shown alongside the cursor, or potentially another convenient location.
 *
 * Fields can be created by calling [PluginContext](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#PluginContext).`createMeasuredField`
 * or [PluginContext](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#PluginContext).`createCustomField`.
 *
 * @internal
 */
export interface Field<FieldValueType = unknown> {
  /**
   * This property controls the order of the field when arranged for display alongside other fields.
   *
   * @see [knownFieldDisplayOrders](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#knownFieldDisplayOrders)
   * @internal
   */
  displayOrder: number;
  /**
   * This should be set to `true` when a field is available for feedback
   * only.
   *
   * @internal
   */
  readOnly: boolean;
  /**
   * Controls whether the value can be locked by the user.
   * This should be set if the field is editable (not read-only)
   * and the plugin will ever call `setValue`.
   *
   * @internal
   */
  lockable: boolean;
  /**
   * If true, the field will be automatically unlocked
   * when the drawing system detects that a vertex has been
   * added in response to user action.
   *
   * @internal
   */
  unlockOnVertexPlacement: boolean;
  /**
   * Sets the actual value for the field.
   *
   * @param value - value to set
   * @internal
   */
  setActual(value: FieldValueType | null | undefined): void;
  /**
   * Gets the value 'locked' by the user, if any.
   *
   * @internal
   */
  getCommitted(): FieldValueType | null | undefined;
  /**
   * Gets the actual value that has been set by the plugin, if any.
   *
   * @internal
   */
  getActual(): FieldValueType | null | undefined;
  /**
   * Gets the value set by the user, if any.
   *
   * @internal
   */
  getInput(): string | null | undefined;
  /**
   * Parses a string into a value to be stored in the field.
   *
   * @internal
   */
  parse?: TooltipField<FieldValueType>["parse"];
  /**
   * Function which formats a quantity into a string for display when in numerical
   * feedback mode.
   *
   * @internal
   */
  format?: TooltipField<FieldValueType>["format"];
  /**
   * Function which formats a quantity into a string for display in the tooltip when in numerical
   * input mode. It should be in the input units and should not include the unit suffix/abbreviation.
   *
   * @internal
   */
  formatForInputMode?: TooltipField<FieldValueType>["formatForInputMode"];
  /**
   * A string or a function which returns a string to be displayed as a suffix next to the field
   * input. Typically used to display an abbreviation of the input units.
   *
   * @internal
   */
  suffix?: TooltipField<FieldValueType>["suffix"];
  /**
   * Title for the field, or a function that produces a title.
   *
   * This can be omitted if using a built-in/preset field.
   *
   * @internal
   */
  title?: TooltipField<FieldValueType>["title"];
  /**
   * Hides this field. This should be used for fields that are contextually not appropriate for display.
   * For example, a radius field for a plugin that can toggle between drawing circles and squares.
   *
   * Important: do not call this in the body of a measurement or watch callback passed to `createMeasuredField`.
   * The measurement system will _not_ monitor property changes for fields that are hidden; this is
   * a critical performance optimization. Therefore, if a field has been hidden, code that relies on a
   * watch/measurement callback to show the field will never be run.
   *
   * @internal
   */
  hide(): void;
  /**
   * Shows this field.
   *
   * Important: do not call this in the body of a measurement or watch callback passed to `createMeasuredField`.
   * The measurement system will _not_ monitor property changes for fields that are hidden; this is
   * a critical performance optimization. Therefore, if a field has been hidden, code that relies on a
   * watch/measurement callback to show the field will never be run.
   *
   * @internal
   */
  show(): void;
}

/**
 * Properties for configuring a field.
 *
 * @internal
 */
export interface MeasuredFieldConfigurationProperties<FieldValueType = unknown, WatchedValueType = unknown> {
  /**
   * Unique identifier for the field
   *
   * @internal
   */
  id: Symbol;
  /**
   * Field preset
   *
   * @internal
   */
  preset?: FieldPreset | null;
  /**
   * This watch will be used to determine when the measurement needs to be updated.
   * When any accessor properties accessed by the callback change, the callback will be
   * re-run and the new value will be passed to a call to the provided measurement callback
   *
   * @internal
   */
  getMeasurementInput: ReactiveWatchExpression<WatchedValueType>;
  /**
   * Measurement callback that will be run whenever the system determines the measurement needs
   * to be refreshed. That is determined by monitoring the visibility of the field, the state of
   * the field system, and changes to properties accessed by the watch callback.
   *
   * @internal
   */
  measure: (newValue: WatchedValueType, fieldContext: TooltipFieldContext, oldValue?: WatchedValueType) => Promise<FieldValueType | null | undefined>;
  /**
   * Properties used to configure the field
   *
   * @internal
   */
  fieldProperties?: Partial<CustomFieldProperties<FieldValueType>>;
  /**
   * Properties used to filter the field to apply to only handles of a certain name or role.
   *
   * @internal
   */
  fieldFilters?: CustomFieldAppliesToProperties;
}

/**
 * Represents the information that is captured when a
 * DrawTool plugin is canceled with the intent to restart it.
 *
 * Persistent state is furnished by [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`suspend`.
 * `CurrentInternalStep` and `persistentSessionState` are managed by DrawTool
 * as part of the undo/redo process when plugins have defined internal/custom undo/redo steps.
 *
 * @internal
 * @see [EditSession](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#EditSession).`pushUndoStep`
 */
export interface PluginRestartInfo<PluginState extends object = {}> {}

/** @internal */
export interface PluginBeforeAttachResult {
  /** @internal */
  useStandaloneSession?: boolean;
  /** @internal */
  pluginConfiguration?: PluginConfiguration;
  /** @internal */
  geometryType?: "point" | "multipoint" | "polyline" | "polygon" | "mesh";
}

/** @internal */
export interface PluginBeforeCompleteResult {
  /** @internal */
  downstreamPluginCompletionMode?: "complete" | "cancel";
}

/**
 * Context object passed to custom constraint functions.
 *
 * @internal
 * @see [PluginContext](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#PluginContext).`createConstraint`
 */
export interface CustomConstraintContext {
  /**
   * The interactive handle the custom constraint callback is being called for.
   * This may be associated with a different plugin than the one that created the constraint.
   *
   * @internal
   */
  handle: InteractiveHandle;
  /**
   * The edit session associated with the current point/interactive handle
   * being constrained.
   *
   * @internal
   */
  editSession: ReadonlyEditSession;
  /**
   * Helper to map geographic points to positions on screen. Positions are relative to
   * the view's frame.
   *
   * @param point - Point to get the screen position of
   * @returns Screenpoint or null if it was not possible to find the point on screen
   * @internal
   */
  toScreen(point: Point): ScreenPoint | null | undefined;
}

/**
 * A callback implementing a minimal snapping-like constraint for
 * interactive handles.
 *
 * @param point - The point to constrain
 * @param context - Information about the source of the point, including the associated handle and edit session
 *                that may be useful in implementing the constraint.
 * @internal
 */
export type CustomConstraintCallback = (point: Point, context: CustomConstraintContext) => Point | null | undefined;

/** @internal */
export type InteractiveHandleConfigurationProperties = Pick<InteractiveHandle, "defaultCaptureMode" | "role" | "snappingEnabled" | "inputMapPosition" | "selfSnappingEnabled" | "name">;

/**
 * This object is passed to plugins on startup and provides the APIs needed to work with the editing
 * system. This includes APIs for editing and inspecting geometry, cooperating with other plugins,
 * visualizing geometry, setting up interactive handles for capturing user input, defining custom
 * fields, measuring geometries, and more besides.
 *
 * @internal
 */
export interface PluginContext {
  /**
   * Gets the plugin's own edit session.
   *
   * This session can change on subsequent calls to `start`. Plugins should not store a reference
   * to this object; instead, always access it by using the latest context object passed to `start`.
   *
   * @internal
   */
  session: EditSession;
  /**
   * Gets a read-only view into the EditSession for another plugin.
   *
   * @param plugin - Plugin to get the read-only session for.
   * @returns Read-only session, or null or undefined
   * @internal
   */
  getSession(plugin: Plugin): ReadonlyEditSession | null | undefined;
  /**
   * Gets the last-seen on-map user input position at time of plugin startup.
   *
   * @internal
   */
  positionOfLastUserInput?: Point | null;
  /**
   * Use this method to set up interactive handles that will be used to capture user input.
   *
   * By default, handles will be configured with x/y/z fields, unless opted out using the options
   * parameter.
   *
   * The `role` property controls both the appearance and several aspects of the behavior of the handle.
   * In general, `"primary"` should be used for handles that correspond directly with a vertex/point/curve endpoint
   * in the produced geometry. `"secondary"` should be used for handles that have an indirect relationship to the
   * geometry, for example representing a control point, or a parameter that will be used to generate geometry.
   *
   * @param properties - properties to configure the handle
   * @param options - additional options that control how the handle is set up
   * @returns The interactive handle
   * @internal
   */
  createInteractiveHandle(properties: Partial<InteractiveHandleConfigurationProperties>, options?: { disableDefaultXYFields?: boolean; }): InteractiveHandle;
  /**
   * Removes an interactive handle.
   *
   * @param handle
   * @internal
   */
  removeInteractiveHandle(handle: InteractiveHandle): void;
  /**
   * Creates a constraint that can be used to apply snapping-like behavior to interactive handles.
   *
   * Custom constraints will be applied after snapping and before
   * all field-derived constraints. In other words, field constraints will
   * win.
   *
   * You might want to use this to implement specialized
   * behavior for a particular plugin. For example, a polygon plugin will 'snap' to the
   * polygon's first vertex.
   *
   * If the constraint has previously been registered for the plugin instance, this is a no-op,
   * unless the constraint has since been removed. In other words, this method is safe to call multiple
   * times during the suspend/resume process.
   *
   * @param id - A uniquely identifying symbol for this constraint.
   * @param callback - A function to call when an interactive handle is moved, after snapping
   *                 is applied and before other constraints are applied.
   * @internal
   */
  createConstraint(id: Symbol, callback: CustomConstraintCallback): void;
  /**
   * Removes a previously set up constraint.
   *
   * @param id - Identifier for the constraint to remove
   * @internal
   */
  removeConstraint(id: Symbol): void;
  /**
   * Sets up field that can be used to show feedback and get user input. You can configure
   * custom field properties, or specify a preset field by name.
   * Field presets can include special behavior that influences the drawing
   * system automatically. For example, some built-in fields include the ability
   * to lock a value, which will be applied to the active cursor.
   *
   * Common examples of fields are for length/area measurements,
   * deflection/angles, and precise coordinate entry/feedback.
   *
   * Plugins should, in general, avoid reliance on custom fields unless the
   * application is prepared to ensure that fields are available for display.
   * Tooltips are the primary in-box way that fields are typically displayed, and
   * these are opt-in by default.
   *
   * Fields can be limited to a specific [InteractiveHandle](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#InteractiveHandle) kind
   * or by handle name with the `appliesToHandlesWithRole` and `appliesToHandlesWithName` properties. If left undefined,
   * the field will be made available to all handles.
   *
   * This is useful in plugins where certain fields only make sense for the primary handle.
   * E.g. the deflection field and constraint usually only make sense for the primary handle and not
   * bezier control points. Similarly, some fields may only make sense for secondary handles, like specific curve parameters.
   *
   * @param properties - Properties to set up the custom field.
   * @internal
   */
  createCustomField<FieldValueType = Angle | Length | ScalarQuantity | string>(properties: Exclude<MeasuredFieldConfigurationProperties<FieldValueType, unknown>, "watch" | "measure">): Field<FieldValueType>;
  /**
   * Sets up a field that is associated with some measurement value. A reactive watch is used to gather
   * the inputs to the measurement; whenever these change, the measurement will be re-run.
   *
   * Any measurement will be paused automatically when the
   * field is not visible to the user. Asynchronous measurements are
   * debounced automatically.
   *
   * @param properties - Properties to set up the measured field
   * @internal
   */
  createMeasuredField<FieldValueType = Angle | Length | ScalarQuantity, WatchedValueType = unknown>(properties: MeasuredFieldConfigurationProperties<FieldValueType, WatchedValueType>): Field<FieldValueType>;
  /**
   * Plugins should call this method when they have reached a state where they are naturally complete,
   * or unable to complete and should be canceled.
   *
   * The drawing system may call the plugin's `complete` method at any time.
   * Plugins must not assume that all completions were initiated by this method.
   *
   * This method is named `request` because the operation is merely requested. In the event that
   * the completion conditions were met while canceling, the plugin will be canceled instead.
   *
   * @internal
   */
  requestComplete: () => void;
  /**
   * Plugins should call this method when they have reached a state where they are naturally
   * unable to complete and should be canceled.
   *
   * The drawing system may call the plugin's `cancel` method at any time.
   * Plugins must not assume that all cancellations were initiated by this method.
   *
   * @internal
   */
  requestCancel: (options?: { preferRestart: boolean; }) => void;
  /**
   * Plugins can use this method to request creation and attach of a downstream plugin.
   * If there is already a plugin attached, it will be canceled and replaced if
   * `options.cancelExisting` parameter is true.
   *
   * If this method is called while the plugin has been scheduled for complete or cancel,
   * the request will be ignored.
   *
   * See [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`beforeAttachPlugin` for options to configure plugins scheduled for attach.
   *
   * Examples of when this is useful:
   * - A distance-distance plugin wants to start a circle plugin to define the first distance
   * - A polyline plugin wants to immediately restart its child plugin upon completion to allow continuous drawing
   *
   * @param configuration - Plugin configuration describing the plugin to start
   * @param options - `cancelExisting` Determines whether this request will cancel any existing downstream plugins
   * @internal
   */
  requestBeginDownstreamPlugin(configuration: PluginConfiguration, options?: { cancelExisting?: boolean; }): void;
  /**
   * This utility enables asynchronous measurement of geometry lengths and distances.
   *
   * This is particularly useful for enabling the implementation of tooltips.
   *
   * @param geometry - The geometry to measure
   * @param cancellationGroup - Key identifying this measurement request for cancellation purposes.
   *                          If this method is called again for the same cancellation group, pending
   *                          requests will be aborted. This is important in cases where the geometry
   *                          is updated faster than the measurement can be completed.
   * @param role - If set to tooltip, measurement requests will be ignored if tooltips are not enabled.
   * @param unit - Unit; defaults to meters if not otherwise specified. If used in
   *             the context of tooltips, be sure to use the correct unit of measure,
   *             or be prepared to convert to the correct unit before display.
   * @internal
   */
  measureLength(geometry: Polyline, cancellationGroup: Symbol, role: "tooltip" | "other", unit?: LengthUnit): Promise<Length | null | undefined>;
  /**
   * This utility enables asynchronous measurement of geometry areas.
   *
   * This is particularly useful for enabling the implementation of tooltips.
   *
   * @param geometry - The geometry to measure
   * @param cancellationGroup - Key identifying this measurement request for cancellation purposes.
   *                          If this method is called again for the same cancellation group, pending
   *                          requests will be aborted. This is important in cases where the geometry
   *                          is updated faster than the measurement can be completed.
   * @param role - If set to tooltip, measurement requests will be ignored if tooltips are not enabled.
   * @param unit - Unit; defaults to meters if not otherwise specified. If used in
   *             the context of tooltips, be sure to use the correct unit of measure,
   *             or be prepared to convert to the correct unit before display.
   * @internal
   */
  measureArea(geometry: Polygon, cancellationGroup: Symbol, role: "tooltip" | "other", unit?: AreaUnit): Promise<Area | null | undefined>;
  /**
   * This utility enables asynchronous measurement of distances between points.
   *
   * This is particularly useful for enabling the implementation of tooltips.
   *
   * @param points - The two points, distance between which will be measured.
   * @param cancellationGroup - Key identifying this measurement request for cancellation purposes.
   *                          If this method is called again for the same cancellation group, pending
   *                          requests will be aborted. This is important in cases where the geometry
   *                          is updated faster than the measurement can be completed.
   * @param role - If set to tooltip, measurement requests will be ignored if tooltips are not enabled.
   * @param unit - Unit; defaults to meters if not otherwise specified. If used in
   *             the context of tooltips, be sure to use the correct unit of measure,
   *             or be prepared to convert to the correct unit before display.
   * @internal
   */
  measureDistance(points: [
      Point,
      Point
  ], cancellationGroup: Symbol, role: "tooltip" | "other", unit?: LengthUnit): Promise<Length | null | undefined>;
  /**
   * This utility measures the elevation of a point, or gets the default elevation.
   *
   * @param point - Point to get the elevation of.
   * @param unit - Unit; defaults to meters if not otherwise specified. If used in
   *             the context of tooltips, be sure to use the correct unit of measure.
   * @internal
   */
  measureElevation(point: Point, unit?: LengthUnit): Length | null | undefined;
  /**
   * Use this method to access global modifier state,
   * for example whether to preserve aspect ratio or center shapes.
   *
   * @internal
   */
  getGlobalState(): GlobalState;
  /**
   * Adds or updates a visual defined in terms of its geometry and symbol. The
   * DrawTool renderer creates a `Graphic` with these properties and
   * displays it in the view.
   *
   * The `id` parameter uniquely identifies a visual in the context of the
   * DrawTool instance. The first time `addOrUpdateGraphic` is called with a
   * given `id`, a new instance of `Graphic` is created and added to the map.
   * Subsequent calls to `addOrUpdateGraphic` with the same `id` will update the
   * properties of the existing `Graphic` instance.
   *
   * When updating a visual, only the properties provided in the `props`
   * parameter are modified; any properties not included in `props` remain
   * unchanged.
   *
   * @param id - An identifier for this graphic.
   * @param props - The properties to set on the corresponding `Graphic`.
   * @internal
   */
  addOrUpdateGraphic(id: Symbol, props: Partial<DrawToolGraphicProperties>): void;
  /**
   * Adds or updates a visual defined in terms of its function or purpose in the
   * drawing workflow. The caller specifies the `role` of the visual — e.g.
   * "cursor", "vertex", "outline" — and its current `state` — e.g. "active",
   * "idle", or "focused". The DrawTool renderer determines how a visual with
   * the given properties should be styled and displays a corresponding
   * [Graphic](https://developers.arcgis.com/javascript/latest/references/core/Graphic/) or other visual in the view.
   *
   * The `id` parameter uniquely identifies a visual in the context of the
   * DrawTool instance. The first time `addOrUpdateGraphic` is called with a
   * given `id`, a new visual is created and added to the map. Subsequent calls
   * using the same `id` result in the existing visual being updated.
   *
   * When updating a visual, only the properties provided in the `props`
   * parameter are modified; any properties not included in `props` remain
   * unchanged.
   *
   * @param id - An identifier for this visual.
   * @param props - The properties describing the visual.
   * @internal
   */
  addOrUpdateVisual(id: Symbol, props: Partial<DrawToolVisualProperties>): void;
  /**
   * Removes a graphic previously added via `addOrUpdateGraphic`.
   *
   * @param id - The identifier for the graphic to remove.
   * @internal
   */
  removeGraphic(id: Symbol): void;
  /**
   * Removes a visual previously added via `addOrUpdateVisual`.
   *
   * @param id - The identifier for the visual to remove.
   * @internal
   */
  removeVisual(id: Symbol): void;
  /**
   * Gets information about the view.
   *
   * @internal
   */
  getViewInformation(): Pick<MapViewOrSceneView, "resolution" | "type" | "center" | "scale" | "extent">;
  /**
   * Gets a special 2D plane that can be used for drawing. The coordinate system
   * knows how to project coordinates correctly to enable, for example,
   * drawing shapes in 3D.
   *
   * @param origin - point defines the origin of the surface coordinate system
   * @internal
   */
  getViewAlignedSurfaceCoordinateSystem(origin: Point): SurfaceCoordinateSystem | null | undefined;
}

/**
 * Plugins implement a portion of a sketching/drawing workflow. A typical workflow
 * will involve multiple plugins working together to create a complete geometry.
 *
 * Plugins may be chained together in a parent-child relationship, where the parent
 * plugin coordinates the overall workflow, either taking action after the child
 * modifies the geometry, or alternatively consuming the result of a child plugin
 * to produce its own contribution.
 *
 * This interface enables applications to inject custom tools to enable advanced editing workflows,
 * without needing to reinvent the basics.
 *
 * > To ensure proper tracking and reactivity, plugins should be implemented as Accessor subclasses,
 * > and the properties of this interface must be implemented as class members with the `@property` decorator.
 * > See [Implementing Accessor](https://developers.arcgis.com/javascript/latest/implementing-accessor/) for details on
 * > implementing an Accessor subclass.
 *
 * @internal
 */
export interface Plugin<PersistentState extends object = {}> extends Accessor {
  /**
   * Called by the drawing system when an operation (typically undo or redo) will
   * cause changes to the underlying geometry data structure that the plugin is not equipped
   * to respond to in a granular manner.
   *
   * In these cases, the plugin will be suspended, the change will be applied, and
   * `start` will be called on the plugin.
   *
   * Every time `start` is called, the plugin must perform initial setup as if it was being set
   * up for the first time. The [PluginContext](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#PluginContext) will automatically
   * manage optimization of provided resources; for example, avoiding re-creating cursors from scratch
   * every time.
   *
   * Plugins _must not_ retain references to [EditSession](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#EditSession) instances
   * after `suspend` is called, whether or not the plugin implements this method. In other words,
   * the [EditSession](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#EditSession) instance is replaced with a new instance
   * on every suspend/start cycle.
   *
   * Optionally, `suspend` may return a state object that will be passed when `start` is called.
   * Plugins must not assume that `start` will be called on the same instance that `suspend` was
   * called on; whether or not the plugin instance is retained or re-created after suspend is an
   * implementation detail that is subject to change.
   *
   * If the plugin is prepared to handle changes to the geometry data structure,
   * set [EditSession](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#EditSession).`automaticRestart` to `false`
   * and implement [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`afterUndoRedo`.
   *
   * Plugins should not proactively clean up or dispose resources acquired through
   * the provided context during this call unless there is a specific need to do so.
   * Context APIs will, where possible, maintain cursors, graphics, and other
   * resources across restarts/suspend-resume cycles to minimize overhead.
   *
   * @returns an object with plugin state that should be passed
   * to a future instance of this plugin, or null if no special state is needed.
   * @see [EditSession](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#EditSession) `pushUndoStep` and `automaticRestart`
   * @internal
   */
  suspend?(): PersistentState | null | undefined;
  /**
   * Called by the drawing system after an undo or redo operation has occurred.
   *
   * This will only be called if the plugin was not restarted automatically.
   *
   * If necessary, the plugin must update its internal state for correctness
   * to account for changes to the geometry.
   *
   * For example, a plugin that computes a tangent curve might need to
   * recompute its parameters if the previous segment has been changed.
   *
   * @param operation - The operation that was performed, either "undo" or "redo".
   * @internal
   */
  afterUndoRedo?(operation: "undo" | "redo"): void;
  /**
   * Called by the drawing system before a downstream plugin plugin is started.
   *
   * This plugin may inspect the incoming plugin to make a decision about whether to
   * use a standalone or a shared edit session, or even modify the plugin configuration.
   *
   * If this method is not implemented, DrawTool will use a shared edit session by default.
   *
   * @param pluginConfiguration - The configuration of the plugin about to be started.
   * @internal
   */
  beforeAttachPlugin?(pluginConfiguration: PluginConfiguration): PluginBeforeAttachResult | null | undefined;
  /**
   * Called when the plugin is about to become active.
   *
   * Note that some workflows involve automatically suspending and restarting plugins. This simplifies
   * implementation of undo/redo behavior; plugins only need to know how to set themselves up
   * given a certain starting state, not how to detect underlying changes and heal incorrect state.
   *
   * This method is called both in cases where the plugin is being started for the first time,
   * and when it is being restarted after a suspend.
   *
   * @param context - Information and utilities needed to implement a plugin.
   * @param persistentState - Optional state object previously returned by `suspend`.
   * @internal
   */
  start(context: PluginContext, persistentState?: PersistentState): void;
  /**
   * Called by the drawing system upon user request, or when requested by the plugin
   * through [PluginContext](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#PluginContext).`requestComplete`.
   *
   * Plugins should not call this method directly; scheduling through the context APIs
   * avoids re-entrance issues and ensures proper sequencing of operations.
   *
   * @internal
   */
  complete(): void;
  /**
   * Called by the drawing system upon user request, or when requested by the plugin
   * through [PluginContext](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#PluginContext).`requestCancel`.
   *
   * Plugins should not call this method directly; scheduling through the context APIs
   * avoids re-entrance issues and ensures proper sequencing of operations.
   *
   * Canceling a parent plugin will result in the downstream plugin chain being canceled as well.
   *
   * The plugin must not perform async work here. Any long-running tasks should be canceled.
   *
   * This method will not be called when the plugin is being restarted as part of an undo/redo operation.
   * Instead, use [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`suspend` to capture any state that should be preserved for the restart.
   *
   * Implementation of this callback is optional. Cleanup of any managed objects and reactive watches
   * should be done with `destroy`, either explicitly or by using utilities like `addhandles`.
   *
   * @internal
   */
  cancel?(): void;
  /**
   * Called by the drawing system upon user request, if this method is implemented.
   *
   * If a plugin requires multiple steps to complete, it should implement
   * this method to advance to the next step.
   *
   * If the method is not implemented, the drawing system
   * will call `complete` when the user requests completion.
   *
   * The plugin may perform async work here, but should be prepared to respect
   * the abort signal and keep the `updating` property updated appropriately.
   *
   * @internal
   */
  completeStep?(): void;
  /**
   * Called by the drawing system before completion. This is an opportunity for the
   * plugin to influence how downstream plugins are handled.
   *
   * By default, all plugins are canceled. If the plugin should automatically complete
   * downstream plugins, implement this method and return the appropriate result.
   *
   * Implementations must not take action or produce side effects when this method
   * is called; this method may be called at any time, and may or may not actually
   * precede plugin completion.
   *
   * @internal
   */
  beforeComplete?(): PluginBeforeCompleteResult | null | undefined;
  /**
   * Called by the drawing system when a plugin was activated while this plugin was the latest active plugin.
   *
   * A plugin might use this method to set up watchers for changes to the downstream session's geometry (via [EditSession](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#EditSession)).
   *
   * Note: in cases where the downstream plugin is suspended/resumed automatically as part of an undo/redo operation,
   * this method will be called again with the new plugin, which may be the same instance as before.
   *
   * @param plugin - The downstream plugin that was just attached.
   * @internal
   */
  attachPlugin?(plugin: Plugin): void;
  /**
   * Called by the drawing system when a downstream plugin has completed or been canceled.
   *
   * A plugin might use this method to clean up watchers set up in [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`attachPlugin.
   * It might also, for example, inspect the geometry produced by the
   * downstream plugin in a disconnected edit session
   * and integrate it into its own edit session.
   *
   * Plugin implementations may use [PluginContext](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#PluginContext).`getSession` to
   * inspect the edit session used by the downstream plugin.
   *
   * @param plugin - The downstream plugin that was just detached.
   * @param status - Indicates whether the plugin completed normally, was canceled, or is being restarted.
   * @internal
   */
  detachPlugin?(plugin: Plugin, status?: "complete" | "cancel"): void;
  /**
   * The configuration used to create this plugin instance.
   * This property will be set before the plugin is started and should not be changed.
   *
   * This property is often important because specific drawing scenarios (e.g. circle vs ellipse)
   * are represented by unique configurations referring to the same plugin implementation.
   *
   * For example, the built-in circle and rectangle plugins both use the same
   * plugin implementation, but have different configurations, allowing the plugin
   * to be presented correctly in relevant UI.
   *
   * @internal
   */
  configuration?: PluginConfiguration | null;
  /**
   * Should return `true` if there are any ongoing asynchronous operations.
   *
   * @internal
   */
  get updating(): boolean;
}

/**
 * Information about a point or vertex in a geometry.
 *
 * @internal
 */
export interface ExtendedPointInfo {
  /**
   * The point at the inspected location.
   *
   * @internal
   */
  point: Point;
  /**
   * The true curve defining an edge leading to the end point `point`, if any. This is returned
   * in the underlying format used by `Polygon.curveRings` and `Polyline.curvePaths`,
   * which is also the JSON representation used by ArcGIS Portal/REST APIs.
   *
   * If the edge leading to this point is not a curve, this property will be undefined.
   *
   * @internal
   * @see [Polygon.curveRings](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polygon/#curveRings)
   * @see [Polyline.curvePaths](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polyline/#curvePaths)
   */
  curveInfo?: CircularArc | EllipticArc4 | EllipticArc7 | BezierCurve;
  /**
   * The zero-based index of the part in a multi-part geometry.
   *
   * 'Parts' corresponds to 'paths' in polyline geometries, 'rings' in polygon geometries,
   * and 'points' in multipoint geometries.
   *
   * @internal
   */
  partIndex?: number;
  /**
   * The zero-based index of the point/vertex within its part.
   *
   * @internal
   */
  pointIndex?: number;
}

/**
 * An edit session provides an interface to inspect and manipulate
 * the geometry being edited by a plugin as part of an editing workflow.
 *
 * @internal
 */
export interface EditSession {
  /**
   * Controls what happens to the plugin's operations when undoing or redoing.
   *
   * Plugins can be thought of as being in a 'staged' or 'completed' state:
   *
   * - `staged`: the plugin state represents the leading edge of what the user is editing.
   *             In this state, undo/redo shouldn't just cancel the plugin's work, but seek
   *             back to undo the last completed undoable step
   * - `committed`: the user indicated that the input to the plugin is complete in some way,
   *                for example by double-clicking or pressing 'f'. In this state, undo/redo
   *                should just undo/redo the plugin's operations as usual.
   *
   * There are two ways a plugin can implement the `staged` behavior:
   *
   * 1. Set this property to `true` (the default). In this case, the plugin's operations
   *    will be undone completely on undo, then the last operation before the plugin's session
   *    will be undone, and the plugin will be restarted.
   *    Note: custom undo steps pushed using `pushUndoStep` will not be undone if this property is `true`.
   * 2. Add custom undo steps using `pushUndoStep`. In this case, each attempt to undo will undo
   *    the next custom undo step, before proceeding to undo the last operation before the
   *    plugin's session once the custom steps are exhausted.
   *
   * If this property is `false` and there are no custom undo steps, undoing will undo the
   * last operation applied to the edit geometry and notify the plugin by calling
   * [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`afterUndoRedo`. Plugins may need to adjust their internal state
   * as the underlying geometry would have likely changed.
   *
   * Note: As of 5.0, undoing will always operate on the shared edit geometry. Granular undo/redo
   * of edits made to disconnected edit sessions is not supported.
   * DrawTool plugins will be restarted until the plugin owning the
   * last operation on the shared edit session is found.
   *
   * @see [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`afterUndoRedo`
   * @see [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`suspend`
   * @internal
   */
  automaticRestart: boolean;
  /**
   * Influences undo/redo behavior.
   *
   * In general, when an operation is applied (e.g. `appendOrReplaceCurve`, `appendOrReplacePoint`, `appendOrReplacePart`),
   * the redo stack is cleared.
   *
   * If a plugin implements internal steps using the `pushUndoStep` feature,
   * it becomes necessary to be able to preserve the redo stack after some operations.
   *
   * The redo stack needs to be purged after any new plugin-internal undo steps,
   * so be sure to set this to false before applying operations that consitute a new step.
   *
   * @internal
   */
  preserveSharedRedoAfterOperation: boolean;
  /**
   * Push an undo step onto the stack. This undo step will be applied before other undo steps.
   *
   * Undo steps should contain enough information to revert the plugin to the state after the
   * undo step was applied; this should be complete, because the state will be applied after
   * the plugin is restarted.
   *
   * The edit session's undo step stack supports complex plugins with multiple input steps,
   * like bezier.
   *
   * When the undo stack has steps, undoing will pop a step, clear the redo stack,
   * restart the plugin, with the undo stack state passed as a parameter, then push the undo step
   * onto the edit session's redo stack.
   *
   * Similarly, redoing will pop a step from the redo stack, restart the plugin with that state,
   * then push the step onto the undo stack.
   *
   * @param state - An object representing the state to be restored when this undo step is applied.
   * @internal
   */
  pushUndoStep(state: object | null | undefined): void;
  /**
   * This method enables plugins to peek at the top undo step.
   *
   * This supports scenarios where a plugin needs to revise the previous
   * undo step before a new one is pushed.
   *
   * In general, the top of the undo stack represents the 'current' step.
   *
   * @internal
   */
  peekUndoStep(): object | null | undefined;
  /**
   * Gets the first vertex that was added by this edit session,
   * for example by calling `appendOrReplacePoint`, `appendOrReplaceCurve`, or `appendOrReplacePart`.
   *
   * "first" is defined by position in the geometry, not necessarily by order
   * of operations, although in most cases this distinction is not significant.
   *
   * @internal
   */
  get firstPointAddedBySession(): ExtendedPointInfo | null | undefined;
  /**
   * Gets the last vertex that was added by this edit session,
   * for example by calling `appendOrReplacePoint`, `appendOrReplaceCurve`, or `appendOrReplacePart`.
   *
   * "last" is defined by position in the geometry, not necessarily by order
   * of operations, although in most cases this distinction is not significant.
   *
   * @internal
   */
  get lastPointAddedBySession(): ExtendedPointInfo | null | undefined;
  /**
   * This method enables plugins to inspect the whole geometry being edited,
   * including portions that were not contributed by this edit session.
   *
   * This is especially useful when a plugin needs to take into account the existing
   * state of the geometry, for example to determine if a new part needs to be inserted.
   *
   * Part index is optional; if omitted, the last part is used.
   *
   * @param pointIndex - zero-based index of the vertex/curve to inspect; negative indices allowed.
   * @param partIndex - optional zero-based index of the part to inspect; if omitted, last part is used.
   * @returns ExtendedPointInfo for the specified vertex/curve, or null if there is no matching result.
   * @internal
   */
  getInformationAboutPoint(pointIndex: number, partIndex?: number): ExtendedPointInfo | null | undefined;
  /**
   * Gets a preview geometry from the `firstPointAddedBySession` to the `lastPointAddedBySession`.
   *
   * There is an option (`includeAutomaticConnection`) to include the segment
   * that the first segment is connected to.
   * This can be used to generate previews of polyline/polygon segments; when `true`,
   * and when there is a connecting segment, the preview will include the start point
   * of the connected segment.
   *
   * Geometry type is disconnected from the plugin's geometry type because sometimes you need a
   * particular view for visualization. For example, if there's only one vertex in a polyline plugin,
   * you may want to see it as a point.
   *
   * @param options - Describes how the preview geometry should be constructed.
   * @internal
   */
  generatePreviewGeometry(options: {
      includeAutomaticConnection: boolean;
      geometryType: "multipoint" | "point" | "polygon" | "polyline";
      firstIncludedPoint?: Pick<ExtendedPointInfo, "partIndex" | "pointIndex"> | null | undefined;
      lastIncludedPoint?: Pick<ExtendedPointInfo, "partIndex" | "pointIndex"> | null | undefined;
  }): Point | Multipoint | Polygon | Polyline | Mesh | null | undefined;
  /**
   * Completes this session and moves all operations and vertices to the parent session.
   *
   * This does not automatically affect undo grouping, or change the geometry in any way.
   *
   * Use `groupGeometryChanges` before completing the session if the operations
   * contributed by this session should be treated as a single undo step.
   *
   * @internal
   */
  complete(): void;
  /**
   * Allows plugins to control how the changes they made to the geometry are
   * undone/redone after the session is completed.
   *
   * When a plugin calls `appendOrReplacePart`, `appendOrReplacePoint`, or `appendOrReplaceCurve`,
   * an internal representation of the operation is added to the undo stack. These changes to the undo stack
   * are temporarily ignored while the plugin is active if `automaticRestart` is `true`.
   * Once the session is completed, these changes contribute to undo behavior.
   *
   * Depending on the nature of the plugin, you may need to control how these geometry changes are
   * treated for undo/redo. For example, a freehand/streaming plugin may add hundreds of points to the geometry;
   * these should be undone using a single undo step.
   *
   * DrawTool plugin authors should consider grouping operations when a logical unit of work is completed,
   * for example when releasing a cursor in a multi-cursor plugin and making adjustments to the shape.
   *
   * @param includeGroups - If true, grouping continues past groups. Otherwise, grouping stops when an existing group is encountered.
   * @internal
   */
  groupGeometryChanges(includeGroups?: boolean): void;
  /**
   * Adds a vertex or sets the position of a vertex if it already exists.
   *
   * The vertex is identified by the handle; if null, a new vertex is added.
   * If forceAppend is true, a new vertex is always added; the new vertex replaces the vertex identified by the given handle.
   *
   * When a vertex is appended, it is always appended to the last part in the geometry.
   *
   * @param handle - A unique symbol that uniquely identifies the vertex in the context of this edit session.
   * @param input - The position of the vertex to add or set.
   * @param options - Additional options affecting behavior.
   * @internal
   */
  appendOrReplacePoint(handle: Symbol | null | undefined, input: Point, options?: { forceAppend: boolean; }): void;
  /**
   * Adds a vertex or sets the position of a vertex if it already exists.
   * The input can include information about the edge leading to the vertex, which can be a true curve.
   *
   * When a vertex is appended, it is always appended to the last part in the geometry.
   * Do not attempt to append a curve to an empty part. All curves must be preceded by at least one vertex (or another curve).
   *
   * @param handle - A unique symbol that uniquely identifies the vertex in the context of this edit session.
   * @param input - The curve definition or coordinate of the vertex to add or set.
   * @param options - Additional options affecting behavior.
   * @internal
   */
  appendOrReplaceCurve(handle: Symbol | null | undefined, input: Curve, options?: { forceAppend: boolean; }): void;
  /**
   * Appends or updates a part, identified by the handle. If the handle is null, a new part is always appended.
   *
   * This method is intended to support multi-part editing by allowing plugins to start a new part.
   * This method is also useful for plugins that create whole parts at a time, for example when
   * creating shapes like circle and rectangle.
   *
   * @param handle - A unique symbol that uniquely identifies the target part in the context of this edit session.
   * @param data - The contents of the part to append or set. Can be empty.
   * @internal
   */
  appendOrReplacePart(handle: Symbol | null | undefined, data: Curve[]): void;
  /**
   * Returns true if the given edit session is operating on the same geometry
   * object as this edit session.
   *
   * This can be a useful check for some custom constraint implementations. For example,
   * the polygon plugin applies a constraint to "snap" the cursor to the closing vertex
   * automatically when it is within a certain distance. This constraint only makes sense
   * when the constrained cursor is part of the same edit session as the polygon being created.
   * The Distance-Distance (circle intersection) plugin draws the circles in a disconnected
   * session, and it doesn't make sense to constrain the cursors used to draw those circles.
   *
   * @param otherSession - The edit session to check.
   * @returns true if the given edit session is operating on the same geometry as this edit session.
   * @internal
   */
  sessionIsOperatingOnSameGeometry(otherSession: EditSession | ReadonlyEditSession | null | undefined): boolean;
  /**
   * Undoes the last operation that was applied to the geometry (typically this
   * includes operations resulting from calls to
   * `appendOrReplaceCurve`, `appendOrReplacePoint`, `appendOrReplacePart`),
   * if and only if the following conditions are met:
   *
   * - There are no active downstream plugins operating on the shared draw tool
   *   geometry
   * - The last applied operation is associated with this edit session
   *
   * The operation will not be added to the redo stack.
   *
   * This method is intended for scenarios where a plugin has completed a change
   * to the shared geometry, but an upstream plugin needs to re-interpret the
   * input to address certain edge cases. In the in-box plugins, this is done when
   * a duplicate point is interactively added by the user, which in typical
   * scenarios is interpreted as a 'complete part' command, rather than a
   * straightforward point append.
   *
   * @internal
   */
  eraseLastOperation(): void;
}

/**
 * An edit session made available for read-only use, generally by a
 * plugin that does not directly own the edit session.
 *
 * Modification of another plugin's edit session is strongly discouraged.
 *
 * If you have a requirement to modify another plugin's edit session,
 * you should expose an API on that plugin and detect the presence of
 * that plugin when [Plugin](https://developers.arcgis.com/javascript/latest/references/core/views/draw/support/types/#Plugin).`attachPlugin` is called.
 *
 * @internal
 */
export type ReadonlyEditSession = Pick<EditSession, "getInformationAboutPoint" | "generatePreviewGeometry" | "firstPointAddedBySession" | "lastPointAddedBySession" | "sessionIsOperatingOnSameGeometry">;

/**
 * Information about a snapping target for a vertex of a feature (or a feature
 * itself, in the case of point features).
 *
 * @internal
 */
export interface VertexSnappingCandidate {}